  1	import * as React from 'react';
  2	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  3	import { ODFSystemFlagsPayload } from '@odf/core/redux/actions';
  4	import { useGetClusterDetails } from '@odf/core/redux/utils';
  5	import { secretResource } from '@odf/core/resources';
  6	import {
  7	  useCustomPrometheusPoll,
  8	  usePrometheusBasePath,
  9	} from '@odf/shared/hooks/custom-prometheus-poll';
 10	import { EventModel } from '@odf/shared/models';
 11	import { K8sResourceKind } from '@odf/shared/types';
 12	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 13	import { getResiliencyProgress } from '@odf/shared/utils';
 14	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 15	import {
 16	  ActivityBody,
 17	  RecentEventsBody,
 18	  OngoingActivityBody,
 19	} from '@openshift-console/dynamic-plugin-sdk-internal';
 20	import { EventKind } from '@openshift-console/dynamic-plugin-sdk-internal/lib/api/internal-types';
 21	import { Card, CardHeader, CardTitle, CardBody } from '@patternfly/react-core';
 22	import {
 23	  dataResiliencyQueryMap,
 24	  ObjectServiceDashboardQuery,
 25	} from '../../../queries';
 26	import { isObjectStorageEvent, decodeRGWPrefix } from '../../../utils';
 27	import { NoobaaDataResiliency } from './data-resiliency-activity/data-resiliency-activity';
 28	import '../../../style.scss';
 29	import './activity-card.scss';
 30	
 31	const eventsResource = { isList: true, kind: EventModel.kind };
 32	
 33	type ActivityProps = {
 34	  systemFlags: ODFSystemFlagsPayload['systemFlags'];
 35	  clusterNs: string;
 36	};
 37	
 38	const RecentEvent: React.FC<ActivityProps> = ({ systemFlags, clusterNs }) => {
 39	  const isRGWSupported = systemFlags[clusterNs]?.isRGWAvailable;
 40	  const isMCGSupported = systemFlags[clusterNs]?.isNoobaaAvailable;
 41	
 42	  const [data, loaded, loadError] =
 43	    useK8sWatchResource<EventKind[]>(eventsResource);
 44	  return (
 45	    <RecentEventsBody
 46	      events={{ data, loaded, loadError }}
 47	      filter={isObjectStorageEvent(isRGWSupported, isMCGSupported)}
 48	    />
 49	  );
 50	};
 51	
 52	const OngoingActivity: React.FC<ActivityProps> = ({
 53	  systemFlags,
 54	  clusterNs,
 55	}) => {
 56	  const isRGWSupported = systemFlags[clusterNs]?.isRGWAvailable;
 57	  const isMCGSupported = systemFlags[clusterNs]?.isNoobaaAvailable;
 58	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
 59	
 60	  const [data, loaded, loadError] = useK8sWatchResource<K8sResourceKind>(
 61	    secretResource(clusterNs)
 62	  );
 63	
 64	  const rgwPrefix = React.useMemo(
 65	    () => (isRGWSupported && loaded && !loadError ? decodeRGWPrefix(data) : ''),
 66	    [data, loaded, loadError, isRGWSupported]
 67	  );
 68	  const rgwResiliencyQuery = dataResiliencyQueryMap[
 69	    ObjectServiceDashboardQuery.RGW_REBUILD_PROGRESS_QUERY
 70	  ](rgwPrefix, managedByOCS);
 71	
 72	  const [progress, progressError] = useCustomPrometheusPoll({
 73	    query: dataResiliencyQueryMap.MCG_REBUILD_PROGRESS_QUERY,
 74	    endpoint: 'api/v1/query' as any,
 75	    basePath: usePrometheusBasePath(),
 76	  });
 77	  const [eta] = useCustomPrometheusPoll({
 78	    query: dataResiliencyQueryMap.MCG_REBUILD_TIME_QUERY,
 79	    endpoint: 'api/v1/query' as any,
 80	    basePath: usePrometheusBasePath(),
 81	  });
 82	  const [rgwProgress, rgwProgressError] = useCustomPrometheusPoll({
 83	    query: rgwResiliencyQuery,
 84	    endpoint: 'api/v1/query' as any,
 85	    basePath: usePrometheusBasePath(),
 86	  });
 87	
 88	  const prometheusActivities = [];
 89	
 90	  if (isMCGSupported && getResiliencyProgress(progress) < 1) {
 91	    prometheusActivities.push({
 92	      results: [progress, eta],
 93	      component: NoobaaDataResiliency,
 94	    });
 95	  }
 96	
 97	  if (isRGWSupported && getResiliencyProgress(rgwProgress) < 1) {
 98	    prometheusActivities.push({
 99	      results: [rgwProgress],
100	      component: NoobaaDataResiliency,
101	    });
102	  }
103	
104	  return (
105	    <OngoingActivityBody
106	      loaded={
107	        (isMCGSupported ? progress || progressError : true) &&
108	        (isRGWSupported ? rgwProgress || rgwProgressError : true)
109	      }
110	      prometheusActivities={prometheusActivities}
111	    />
112	  );
113	};
114	
115	const ActivityCard: React.FC = () => {
116	  const { t } = useCustomTranslation();
117	
118	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
119	  const { systemFlags } = useODFSystemFlagsSelector();
120	
121	  return (
122	    <Card className="odf-overview-card--gradient">
123	      <CardHeader>
124	        <CardTitle>{t('Activity')}</CardTitle>
125	      </CardHeader>
126	      <CardBody>
127	        <ActivityBody className="nb-activity-card__body">
128	          <OngoingActivity systemFlags={systemFlags} clusterNs={clusterNs} />
129	          <RecentEvent systemFlags={systemFlags} clusterNs={clusterNs} />
130	        </ActivityBody>
131	      </CardBody>
132	    </Card>
133	  );
134	};
135	
136	export default ActivityCard;

